#include<bits/stdc++.h>
using namespace std;
int n,m,t[100005],b[1125005],vis[1505][1505],k,tot,mmax,tmp;
char a[1505][1505];
int dx[]={0,-1,-1,-1,0,0,1,1,1};
int dy[]={0,-1,0,1,-1,1,-1,0,1};
void printf()
{
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cout<<vis[i][j]<<" ";
		}
		cout<<"\n";
	}
	cout<<"\n";
}
void dfs(int x,int y)
{
	for(int i=1;i<=8;i++)
	{
		int nx=x+dx[i];
		int ny=y+dy[i];
		if(nx>=1 and ny>=1 and nx<=n and ny<=m and a[nx][ny]=='*' and vis[nx][ny]==0)
		{
			vis[nx][ny]=1;
			tot++;
			dfs(nx,ny);
		}
	}
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			if(a[i][j]=='*' and vis[i][j]==0)
			{
				k++;
				tot=1;
				vis[i][j]=1;
				dfs(i,j);
				t[tot]++;
				tmp=max(tmp,tot);
//				printf();
			}
		}
	}
	k=0;
	for(int i=1;i<=1005;i++)
	{
		if(t[i]!=0)
		{
//			cout<<t[i]<<" ";
			k++;
//			tot++;
			b[k]=t[i]*i;
			mmax=max(b[k],mmax);
//			mmax=mmax(i,mmax);
		}
	}
	cout<<k<<" "<<mmax;
	return 0;
}
